logger = logging.getLogger()
logger.setLevel(os.environ.get("LOG_LEVEL", "INFO"))

ENVIRONMENT = os.environ.get("ENVIRONMENT", "dev")
ALLOWED_ENVIRONMENTS = {"dev", "staging", "prod"}

TABLE_NAME = os.environ.get("DYNAMODB_TABLE_NAME", "")
S3_BUCKET = os.environ.get("S3_BUCKET_NAME", "")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")
SQS_QUEUE_URL = os.environ.get("SQS_QUEUE_URL", "")


def _validate_environment():
    """Validate that required environment variables are set and safe."""
    if ENVIRONMENT not in ALLOWED_ENVIRONMENTS:
        raise ValueError(f"Invalid ENVIRONMENT: {ENVIRONMENT}")
    if not TABLE_NAME:
        raise ValueError("DYNAMODB_TABLE_NAME environment variable is required")
    if not S3_BUCKET:
        raise ValueError("S3_BUCKET_NAME environment variable is required")


def _get_boto3_client(service_name):
    """Create a boto3 client with consistent configuration."""
    return boto3.client(service_name)


def _sanitize_key(key):
    """Sanitize S3 keys and DynamoDB keys to prevent injection."""
    if not isinstance(key, str):
        raise ValueError("Key must be a string")
    if len(key) > 1024:
        raise ValueError("Key exceeds maximum length of 1024 characters")
    # Prevent path traversal in S3 keys
    if ".." in key or key.startswith("/"):
        raise ValueError("Invalid key: path traversal not allowed")
    return key


def _sanitize_string_value(value, max_length=10000):
    """Sanitize string values to prevent oversized payloads."""
    if not isinstance(value, str):
        raise ValueError("Value must be a string")
    if len(value) > max_length:
        raise ValueError(f"Value exceeds maximum length of {max_length}")
    return value


class MicroserviceBase:
    """
    Base class providing shared AWS service interactions for all microservices.
    Each Lambda function can instantiate this to get consistent, secure access
    to S3, DynamoDB, SNS, and SQS using the shared IAM role.
    """

    def __init__(self):
        _validate_environment()
        self._dynamodb = None
        self._s3 = None
        self._sns = None
        self._sqs = None

    @property
    def dynamodb(self):
        if self._dynamodb is None:
            self._dynamodb = boto3.resource("dynamodb")
        return self._dynamodb

    @property
    def s3_client(self):
        if self._s3 is None:
            self._s3 = _get_boto3_client("s3")
        return self._s3

    @property
    def sns_client(self):
        if self._sns is None:
            self._sns = _get_boto3_client("sns")
        return self._sns

    @property
    def sqs_client(self):
        if self._sqs is None:
            self._sqs = _get_boto3_client("sqs")
        return self._sqs

    def get_dynamodb_item(self, key_name, key_value):
        """Retrieve an item from DynamoDB by primary key."""
        key_name = _sanitize_key(key_name)
        key_value = _sanitize_key(key_value)
        table = self.dynamodb.Table(TABLE_NAME)
        try:
            response = table.get_item(Key={key_name: key_value})
            return response.get("Item")
        except ClientError as e:
            logger.error(
                "DynamoDB GetItem failed: %s",
                e.response["Error"]["Message"],
            )
            raise

    def put_dynamodb_item(self, item):
        """Put an item into DynamoDB."""
        if not isinstance(item, dict):
            raise ValueError("Item must be a dictionary")
        if not item:
            raise ValueError("Item cannot be empty")
        table = self.dynamodb.Table(TABLE_NAME)
        try:
            table.put_item(Item=item)
            logger.info("Successfully put item into %s", TABLE_NAME)
        except ClientError as e:
            logger.error(
                "DynamoDB PutItem failed: %s",
                e.response["Error"]["Message"],
            )
            raise

    def query_dynamodb(self, key_condition_expression, expression_values):
        """Query DynamoDB with a key condition expression."""
        table = self.dynamodb.Table(TABLE_NAME)
        try:
            response = table.query(
                KeyConditionExpression=key_condition_expression,
                ExpressionAttributeValues=expression_values,
            )
            return response.get("Items", [])
        except ClientError as e:
            logger.error(
                "DynamoDB Query failed: %s",
                e.response["Error"]["Message"],
            )
            raise

    def get_s3_object(self, key):
        """Retrieve an object from S3."""
        key = _sanitize_key(key)
        try:
            response = self.s3_client.get_object(Bucket=S3_BUCKET, Key=key)
            return response["Body"].read()
        except ClientError as e:
            logger.error(
                "S3 GetObject failed for key '%s': %s",
                key,
                e.response["Error"]["Message"],
            )
            raise

    def put_s3_object(self, key, body, content_type="application/json"):
        """Put an object into S3 with server-side encryption."""
        key = _sanitize_key(key)
        try:
            self.s3_client.put_object(
                Bucket=S3_BUCKET,
                Key=key,
                Body=body,
                ContentType=content_type,
                ServerSideEncryption="aws:kms",
            )
            logger.info("Successfully put object to s3://%s/%s", S3_BUCKET, key)
        except ClientError as e:
            logger.error(
                "S3 PutObject failed for key '%s': %s",
                key,
                e.response["Error"]["Message"],
            )
            raise

    def publish_sns_message(self, message, subject=None, message_attributes=None):
        """Publish a message to the configured SNS topic."""
        if not SNS_TOPIC_ARN:
            raise ValueError("SNS_TOPIC_ARN is not configured")
        if isinstance(message, dict):
            message = json.dumps(message)
        message = _sanitize_string_value(message, max_length=256 * 1024)
        kwargs = {
            "TopicArn": SNS_TOPIC_ARN,
            "Message": message,
        }
        if subject:
            kwargs["Subject"] = _sanitize_string_value(subject, max_length=100)
        if message_attributes:
            kwargs["MessageAttributes"] = message_attributes
        try:
            response = self.sns_client.publish(**kwargs)
            logger.info("Published SNS message: %s", response.get("MessageId"))
            return response.get("MessageId")
        except ClientError as e:
            logger.error(
                "SNS Publish failed: %s",
                e.response["Error"]["Message"],
            )
            raise

    def send_sqs_message(self, message_body, message_group_id=None, deduplication_id=None):
        """Send a message to the configured SQS queue."""
        if not SQS_QUEUE_URL:
            raise ValueError("SQS_QUEUE_URL is not configured")
        if isinstance(message_body, dict):
            message_body = json.dumps(message_body)
        message_body = _sanitize_string_value(message_body, max_length=256 * 1024)
        kwargs = {
            "QueueUrl": SQS_QUEUE_URL,
            "MessageBody": message_body,
        }
        if message_group_id:
            kwargs["MessageGroupId"] = _sanitize_string_value(
                message_group_id, max_length=128
            )
        if deduplication_id:
            kwargs["MessageDeduplicationId"] = _sanitize_string_value(
                deduplication_id, max_length=128
            )
        try:
            response = self.sqs_client.send_message(**kwargs)
            logger.info("Sent SQS message: %s", response.get("MessageId"))
            return response.get("MessageId")
        except ClientError as e:
            logger.error(
                "SQS SendMessage failed: %s",
                e.response["Error"]["Message"],
            )
            raise

    def receive_sqs_messages(self, max_messages=10, wait_time_seconds=5):
        """Receive messages from the configured SQS queue."""
        if not SQS_QUEUE_URL:
            raise ValueError("SQS_QUEUE_URL is not configured")
        max_messages = min(max(1, int(max_messages)), 10)
        wait_time_seconds = min(max(0, int(wait_time_seconds)), 20)
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=SQS_QUEUE_URL,
                MaxNumberOfMessages=max_messages,
                WaitTimeSeconds=wait_time_seconds,
                AttributeNames=["All"],
                MessageAttributeNames=["All"],
            )
            messages = response.get("Messages", [])
            logger.info("Received %d messages from SQS", len(messages))
            return messages
        except ClientError as e:
            logger.error(
                "SQS ReceiveMessage failed: %s",
                e.response["Error"]["Message"],
            )
            raise

    def delete_sqs_message(self, receipt_handle):
        """Delete a processed message from SQS."""
        if not SQS_QUEUE_URL:
            raise ValueError("SQS_QUEUE_URL is not configured")
        if not receipt_handle or not isinstance(receipt_handle, str):
            raise ValueError("Invalid receipt_handle")
        try:
            self.sqs_client.delete_message(
                QueueUrl=SQS_QUEUE_URL,
                ReceiptHandle=receipt_handle,
            )
            logger.info("Deleted SQS message")
        except ClientError as e:
            logger.error(
                "SQS DeleteMessage failed: %s",
                e.response["Error"]["Message"],
            )
            raise


def _build_response(status_code, body, headers=None):
    """Build a standardized API Gateway response."""
    default_headers = {
        "Content-Type": "application/json",
        "X-Content-Type-Options": "nosniff",
        "Strict-Transport-Security": "max-age=63072000; includeSubDomains; preload",
        "Cache-Control": "no-store",
    }
    if headers:
        default_headers.update(headers)
    return {
        "statusCode": status_code,
        "headers": default_headers,
        "body": json.dumps(body) if isinstance(body, dict) else body,
    }


def _extract_and_validate_body(event):
    """Safely extract and parse the request body from an API Gateway event."""
    body = event.get("body")
    if body is None:
        return None
    if isinstance(body, str):
        if len(body) > 1_000_000:
            raise ValueError("Request body too large")
        try:
            return json.loads(body)
        except json.JSONDecodeError:
            raise ValueError("Invalid JSON in request body")
    if isinstance(body, dict):
        return body
    raise ValueError("Unexpected body type")


# Initialize the shared service layer (reused across warm invocations)
_service = None


def _get_service():
    """Lazy-initialize the microservice base (connection reuse across invocations)."""
    global _service
    if _service is None:
        _service = MicroserviceBase()
    return _service


def lambda_handler(event, context):
    """
    Main Lambda handler demonstrating usage of the shared IAM role and
    MicroserviceBase class.

    This example processes incoming events by:
    1. Storing data in DynamoDB
    2. Uploading a copy to S3
    3. Publishing a notification via SNS
    4. Optionally queuing follow-up work via SQS
    """
    logger.info(
        "Lambda invoked: function=%s, request_id=%s",
        context.function_name,
        context.aws_request_id,
    )

    try:
        service = _get_service()

        # Handle API Gateway events
        if "httpMethod" in event:
            return _handle_api_request(event, context, service)

        # Handle SQS trigger events
        if "Records" in event and event["Records"] and \
                event["Records"][0].get("eventSource") == "aws:sqs":
            return _handle_sqs_event(event, context, service)

        # Handle SNS trigger events
        if "Records" in event and event["Records"] and \
                event["Records"][0].get("EventSource") == "aws:sns":
            return _handle_sns_event(event, context, service)

        # Handle direct invocation
        return _handle_direct_invocation(event, context, service)

    except ValueError as e:
        logger.warning("Validation error: %s", str(e))
        return _build_response(400, {"error": "Bad Request", "message": str(e)})
    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        logger.error("AWS service error: %s - %s", error_code, str(e))
        if error_code in ("AccessDeniedException", "UnauthorizedAccess"):
            return _build_response(
                403, {"error": "Forbidden", "message": "Access denied"}
            )
        return _build_response(
            500, {"error": "Internal Server Error", "message": "Service unavailable"}
        )
    except Exception:
        logger.exception("Unhandled exception in lambda_handler")
        return _build_response(
            500,
            {"error": "Internal Server Error", "message": "An unexpected error occurred"},
        )


def _handle_api_request(event, context, service):
    """Handle API Gateway HTTP requests."""
    http_method = event.get("httpMethod", "")
    path = event.get("path", "")
    logger.info("API request: %s %s", http_method, path)

    if http_method == "GET":
        path_params = event.get("pathParameters") or {}
        item_id = path_params.get("id")
        if not item_id:
            return _build_response(400, {"error": "Missing 'id' path parameter"})
        item_id = _sanitize_key(item_id)
        item = service.get_dynamodb_item("id", item_id)
        if item is None:
            return _build_response(404, {"error": "Item not found"})
        return _build_response(200, {"data": item})

    elif http_method == "POST":
        body = _extract_and_validate_body(event)
        if not body:
            return _build_response(400, {"error": "Request body is required"})

        item_id = body.get("id")
        if not item_id:
            return _build_response(400, {"error": "Field 'id' is required"})

        item_id = _sanitize_key(str(item_id))
        item = {
            "id": item_id,
            "data": body.get("data", {}),
            "environment": ENVIRONMENT,
            "created_by": context.function_name,
        }

        # Store in DynamoDB
        service.put_dynamodb_item(item)

        # Store a backup copy in S3
        s3_key = f"items/{ENVIRONMENT}/{item_id}.json"
        service.put_s3_object(s3_key, json.dumps(item))

        # Notify downstream services
        if SNS_TOPIC_ARN:
            service.publish_sns_message(
                message={"event": "item_created", "item_id": item_id},
                subject=f"Item Created: {item_id}",
            )

        # Queue async processing if configured
        if SQS_QUEUE_URL:
            service.send_sqs_message(
                message_body={"action": "process_item", "item_id": item_id}
            )

        return _build_response(
            201,
            {"message": "Item created successfully", "id": item_id},
        )

    else:
        return _build_response(
            405, {"error": f"Method {http_method} not allowed"}
        )


def _handle_sqs_event(event, context, service):
    """Handle SQS trigger events (batch processing)."""
    records = event.get("Records", [])
    logger.info("Processing %d SQS records", len(records))

    failures = []
    for record in records:
        message_id = record.get("messageId", "unknown")
        try:
            body = json.loads(record.get("body", "{}"))
            action = body.get("action")
            item_id = body.get("item_id")

            if not action or not item_id:
                logger.warning(
                    "Skipping malformed SQS message %s: missing action or item_id",
                    message_id,
                )
                continue

            item_id = _sanitize_key(str(item_id))
            logger.info(
                "Processing SQS message %s: action=%s, item_id=%s",
                message_id,
                action,
                item_id,
            )

            if action == "process_item":
                item = service.get_dynamodb_item("id", item_id)
                if item:
                    item["processed"] = True
                    item["processed_by"] = context.function_name
                    service.put_dynamodb_item(item)
                    logger.info("Processed item %s", item_id)
                else:
                    logger.warning("Item %s not found for processing", item_id)

        except (json.JSONDecodeError, ValueError) as e:
            logger.error("Failed to process SQS message %s: %s", message_id, str(e))
            failures.append({"itemIdentifier": message_id})
        except ClientError as e:
            logger.error(
                "AWS error processing SQS message %s: %s", message_id, str(e)
            )
            failures.append({"itemIdentifier": message_id})

    # Return partial batch failure response for SQS
    if failures:
        logger.warning("%d SQS messages failed processing", len(failures))
        return {"batchItemFailures": failures}

    return {"batchItemFailures": []}


def _handle_sns_event(event, context, service):
    """Handle SNS trigger events."""
    records = event.get("Records", [])
    logger.info("Processing %d SNS records", len(records))

    for record in records:
        sns_message = record.get("Sns", {})
        message_id = sns_message.get("MessageId", "unknown")
        subject = sns_message.get("Subject", "")
        try:
            message_body = json.loads(sns_message.get("Message", "{}"))
            logger.info(
                "Processing SNS message %s: subject=%s",
                message_id,
                subject,
            )

            event_type = message_body.get("event")
            item_id = message_body.get("item_id")

            if event_type and item_id:
                item_id = _sanitize_key(str(item_id))
                logger.info(
                    "SNS event: type=%s, item_id=%s", event_type, item_id
                )

        except (json.JSONDecodeError, ValueError) as e:
            logger.error(
                "Failed to process SNS message %s: %s", message_id, str(e)
            )

    return {"statusCode": 200, "message": f"Processed {len(records)} SNS records"}


def _handle_direct_invocation(event, context, service):
    """Handle direct Lambda invocations."""
    action = event.get("action")
    logger.info("Direct invocation: action=%s", action)

    if action == "health_check":
        return {
            "status": "healthy",
            "function": context.function_name,
            "environment": ENVIRONMENT,
            "remaining_time_ms": context.get_remaining_time_in_millis(),
        }

    if action == "get_item":
        item_id = event.get("item_id")
        if not item_id:
            return {"error": "item_id is required"}
        item_id = _sanitize_key(str(item_id))
        item = service.get_dynamodb_item("id", item_id)
        return {"data": item} if item else {"error": "Item not found"}

    return {"error": f"Unknown action: {action}"}